+        return SshError::AgentUnavailable {
+            host: worker.host.clone(),
+            user: worker.user.clone(),
+            key_path,
+        };
+    }
+
+    SshError::ConnectionFailed {
+        host: worker.host.clone(),
+        user: worker.user.clone(),
+        key_path,
+        message,
+    }
